#### 任务 2.1: 完善 WebSocket Store（1 天）

**目标**: 确保 WebSocket 连接稳定，事件处理完善

**实现步骤**:

```typescript
// src/stores/websocket.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null)
  const connected = ref(false)
  const connecting = ref(false)
  const reconnecting = ref(false)
  const reconnectAttempts = ref(0)
  const lastError = ref<Error | null>(null)

  const maxReconnectAttempts = 5
  const reconnectDelay = 3000

  // 连接 WebSocket
  async function connect() {
    if (ws.value?.readyState === WebSocket.OPEN) {
      return
    }

    connecting.value = true
    lastError.value = null

    try {
      ws.value = new WebSocket('ws://localhost:3000/api/ws')

      ws.value.onopen = () => {
        connected.value = true
        connecting.value = false
        reconnecting.value = false
        reconnectAttempts.value = 0
        console.log('WebSocket connected')
      }

      ws.value.onmessage = (event) => {
        handleMessage(event.data)
      }

      ws.value.onerror = (error) => {
        lastError.value = new Error('WebSocket error')
        console.error('WebSocket error:', error)
      }

      ws.value.onclose = () => {
        connected.value = false
        connecting.value = false
        console.log('WebSocket closed')

        // 自动重连
        if (reconnectAttempts.value < maxReconnectAttempts) {
          reconnect()
        }
      }
    } catch (error) {
      connecting.value = false
      lastError.value = error as Error
      console.error('Failed to connect:', error)
    }
  }

  // 自动重连
  function reconnect() {
    if (reconnecting.value) return

    reconnecting.value = true
    reconnectAttempts.value++

    setTimeout(() => {
      connect()
    }, reconnectDelay * reconnectAttempts.value)
  }

  // 处理消息
  function handleMessage(data: string) {
    try {
      const { type, data: payload } = JSON.parse(data)

      switch (type) {
        case 'iteration.status_changed':
          // 更新迭代状态
          break
        case 'agent.status_changed':
          // 更新 Agent 状态
          break
        case 'iteration.progress':
          // 更新进度
          break
        case 'log.entry':
          // 添加日志
          break
        default:
          console.warn('Unknown message type:', type)
      }
    } catch (error) {
      console.error('Failed to parse message:', error)
    }
  }

  // 发送消息
  function send(type: string, data: unknown) {
    if (ws.value?.readyState === WebSocket.OPEN) {
      ws.value.send(JSON.stringify({ type, data }))
    }
  }

  // 断开连接
  function disconnect() {
    ws.value?.close()
    ws.value = null
    connected.value = false
  }

  // 获取连接状态文本
  function getConnectionText() {
    if (reconnecting.value) return '重连中...'
    if (connecting.value) return '连接中...'
    if (connected.value) return '已连接'
    return '未连接'
  }

  // 获取连接类型
  function getConnectionType() {
    if (reconnecting.value) return 'warning'
    if (connecting.value) return 'info'
    if (connected.value) return 'success'
    return 'danger'
  }

  return {
    ws,
    connected,
    connecting,
    reconnecting,
    reconnectAttempts,
    lastError,
    connect,
    disconnect,
    send,
    getConnectionText,
    getConnectionType
  }
})
```

