<script setup lang="ts">
import { computed } from 'vue'
import { useAgentStore } from '@/stores/agent'
import AgentStatusCard from '@/components/AgentStatusCard.vue'
import AgentPerformanceChart from '@/components/charts/AgentPerformanceChart.vue'
import SystemResourceChart from '@/components/charts/SystemResourceChart.vue'

const agentStore = useAgentStore()

const runningCount = computed(() => 
  Object.values(agentStore.agents).filter(a => a.status === 'running').length
)

const successRate = computed(() => {
  const agents = Object.values(agentStore.agents)
  const total = agents.reduce((sum, a) => sum + a.executionCount, 0)
  if (total === 0) return 0
  const success = agents.reduce((sum, a) => sum + a.successCount, 0)
  return (success / total) * 100
})

const avgTime = computed(() => {
  const agents = Object.values(agentStore.agents)
  const times = agents.map(a => a.avgExecutionTime).filter(t => t > 0)
  if (times.length === 0) return 0
  return times.reduce((sum, t) => sum + t, 0) / times.length
})

const sortedAgents = computed(() => {
  return Object.values(agentStore.agents).sort((a, b) => {
    // 运行中的排最前
    if (a.status === 'running' && b.status !== 'running') return -1
    if (b.status === 'running' && a.status !== 'running') return 1
    return a.name.localeCompare(b.name)
  })
})

function showAgentDetail(agent: AgentData) {
  // 显示 Agent 详情弹窗
  console.log('Show agent detail:', agent)
}
