// src/dashboard/server/routes/iterations.ts
import { FastifyInstance } from 'fastify'

export async function iterationRoutes(fastify: FastifyInstance) {
  // 获取迭代列表
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, pageSize = 20, status, keyword } = request.query as any

    // 从数据库查询
    const data = await fastify.iterationService.list({
      page,
      pageSize,
      status,
      keyword
    })

    return { success: true, data }
  })

  // 获取迭代详情
  fastify.get('/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string }
    const data = await fastify.iterationService.getById(id)
    return { success: true, data }
  })

  // 回滚迭代
  fastify.post('/iterations/:id/rollback', async (request, reply) => {
    const { id } = request.params as { id: string }
    const result = await fastify.iterationService.rollback(id)
    return { success: true, ...result }
  })

  // 对比迭代
  fastify.get('/iterations/:id1/diff/:id2', async (request, reply) => {
    const { id1, id2 } = request.params as { id1: string; id2: string }
    const data = await fastify.iterationService.diff(id1, id2)
    return { success: true, data }
  })
}
```

