**任务 2.1: WebSocket Store 实现** ⏰ 1.5小时
```typescript
// dashboard/src/stores/websocket.ts

import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { ElMessage } from 'element-plus';

export const useWebSocketStore = defineStore('websocket', () => {
  // State
  const isConnected = ref(false);
  const isConnecting = ref(false);
  const reconnectAttempts = ref(0);
  const maxReconnectAttempts = 5;
  const socket = ref<WebSocket | null>(null);
  const subscriptions = ref<Set<string>>(new Set());

  // Computed
  const connectionStatus = computed(() => {
    if (isConnecting.value) return '连接中...';
    if (isConnected.value) return '已连接';
    return '已断开';
  });

  // 连接
  function connect() {
    if (socket.value?.readyState === WebSocket.OPEN) {
      console.log('WebSocket 已连接');
      return;
    }

    isConnecting.value = true;
    const wsUrl = import.meta.env.VITE_WS_BASE_URL || 'ws://localhost:3000/ws';

    socket.value = new WebSocket(wsUrl);

    socket.value.onopen = () => {
      console.log('✅ WebSocket 已连接');
      isConnected.value = true;
      isConnecting.value = false;
      reconnectAttempts.value = 0;

      ElMessage.success('实时连接已建立');

      // 自动订阅所有频道
      subscribe('iterations');
      subscribe('agents');
      subscribe('logs');
      subscribe('metrics');
    };

    socket.value.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data);
        handleMessage(message);
      } catch (error) {
        console.error('WebSocket 消息解析错误:', error);
      }
    };

    socket.value.onclose = () => {
      console.log('❌ WebSocket 已断开');
      isConnected.value = false;
      isConnecting.value = false;

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        const delay = Math.min(1000 * Math.pow(2, reconnectAttempts.value), 30000);
        setTimeout(() => {
          reconnectAttempts.value++;
          console.log(`🔄 尝试重连 (${reconnectAttempts.value}/${maxReconnectAttempts})...`);
          connect();
        }, delay);
      } else {
        ElMessage.error('连接失败，请刷新页面重试');
      }
    };

    socket.value.onerror = (error) => {
      console.error('WebSocket 错误:', error);
      ElMessage.error('连接错误');
    };
  }

  // 断开
  function disconnect() {
    if (socket.value) {
      socket.value.close();
      socket.value = null;
    }
    isConnected.value = false;
    subscriptions.value.clear();
  }

  // 订阅
  function subscribe(channel: string) {
    if (socket.value?.readyState === WebSocket.OPEN) {
      socket.value.send(JSON.stringify({
        type: 'subscribe',
        channel
      }));
      subscriptions.value.add(channel);
      console.log(`📡 已订阅频道: ${channel}`);
    }
  }

  // 取消订阅
  function unsubscribe(channel: string) {
    if (socket.value?.readyState === WebSocket.OPEN) {
      socket.value.send(JSON.stringify({
        type: 'unsubscribe',
        channel
      }));
      subscriptions.value.delete(channel);
      console.log(`📡 已取消订阅: ${channel}`);
    }
  }

  // 处理消息
  function handleMessage(message: any) {
    const { type, data } = message;

    // 导入其他 Store（避免循环依赖）
    const { useIterationStore } = await import('./iteration');
    const { useAgentStore } = await import('./agent');
    const { useOverviewStore } = await import('./overview');
    const { useLogStore } = await import('./log');

    switch (type) {
      case 'iteration.status_changed':
        useIterationStore().updateIteration(data);
        break;

      case 'iteration.progress':
        useIterationStore().updateProgress(data.id, data.progress);
        break;

      case 'iteration.completed':
        useIterationStore().markIterationCompleted(data);
        ElMessage.success(`迭代 #${data.iteration.iterationNumber} 已完成 🎉`);
        break;

      case 'agent.status_changed':
        useAgentStore().updateAgent(data);
        break;

      case 'agent.progress':
        useAgentStore().updateAgentProgress(data.name, data.progress);
        break;

      case 'system.metrics':
        useOverviewStore().updateMetrics(data);
        break;

      case 'log.entry':
        useLogStore().addLogEntry(data);
        break;

      case 'error':
        ElMessage.error(data.message);
        break;

      case 'ping':
        // 响应心跳
        socket.value?.send(JSON.stringify({ type: 'pong' }));
        break;

      default:
        console.warn('未知消息类型:', type);
    }
  }

  return {
    isConnected,
    isConnecting,
    reconnectAttempts,
    connectionStatus,
    connect,
    disconnect,
    subscribe,
    unsubscribe
  };
});
```

**验收标准**:
- ✅ WebSocket 连接正常
- ✅ 自动重连机制正常
- ✅ 消息分发到 Store 正常

