// dashboard/src/stores/iteration.ts

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([]);
  const currentIteration = ref<Iteration | null>(null);

  // ✅ WebSocket 实时更新
  function updateIteration(iteration: Iteration) {
    const index = iterations.value.findIndex(i => i.id === iteration.id);
    if (index !== -1) {
      iterations.value[index] = iteration;
    } else {
      iterations.value.unshift(iteration);
    }

    // 更新当前迭代
    if (currentIteration.value?.id === iteration.id) {
      currentIteration.value = iteration;
    }
  }

  // ✅ WebSocket 实时进度更新
  function updateProgress(id: string, progress: number) {
    const iteration = iterations.value.find(i => i.id === id);
    if (iteration) {
      iteration.progress = progress;
    }
    if (currentIteration.value?.id === id) {
      currentIteration.value.progress = progress;
    }
  }

  // ✅ WebSocket 标记完成
  function markIterationCompleted(data: any) {
    const { iteration, commitHash } = data;
    updateIteration(iteration);
  }

  return {
    iterations,
    currentIteration,
    updateIteration,
    updateProgress,
    markIterationCompleted
  };
});

