export const useAgentStore = defineStore('agent', () => {
  const agents = ref<Agent[]>([]);

  // ✅ WebSocket 实时更新
  function updateAgent(agent: Agent) {
    const index = agents.value.findIndex(a => a.name === agent.name);
    if (index !== -1) {
      agents.value[index] = agent;
    } else {
      agents.value.push(agent);
    }
  }

  // ✅ WebSocket 进度更新
  function updateAgentProgress(name: string, progress: number) {
    const agent = agents.value.find(a => a.name === name);
    if (agent) {
      agent.progress = progress;
    }
  }

  return {
    agents,
    updateAgent,
    updateAgentProgress
  };
});

// dashboard/src/stores/overview.ts

export const useOverviewStore = defineStore('overview', () => {
  const metrics = ref<SystemMetrics | null>(null);

  // ✅ WebSocket 实时更新
  function updateMetrics(newMetrics: SystemMetrics) {
    metrics.value = newMetrics;
  }

  return {
    metrics,
    updateMetrics
  };
});

// dashboard/src/stores/log.ts

export const useLogStore = defineStore('log', () => {
  const logs = ref<LogEntry[]>([]);
  const maxLogs = 1000;

  // ✅ WebSocket 实时添加
  function addLogEntry(log: LogEntry) {
    logs.value.push(log);

    // 限制日志数量
    if (logs.value.length > maxLogs) {
      logs.value.shift();
    }
  }

  return {
    logs,
    addLogEntry
  };
});
