export async function iterationRoutes(fastify: FastifyInstance, service: IterationService) {
  // GET /iterations - 获取列表
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, pageSize = 20, status, keyword } = request.query as any;

    const result = await service.list({
      page,
      pageSize,
      status,
      keyword
    });

    return reply.send({
      success: true,
      data: result
    });
  });

  // GET /iterations/:id - 获取详情
  fastify.get('/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const iteration = await service.getById(id);

    if (!iteration) {
      return reply.code(404).send({
        success: false,
        error: { message: '迭代不存在' }
      });
    }

    return reply.send({ success: true, data: iteration });
  });

  // POST /iterations/:id/rollback - 回滚
  fastify.post('/iterations/:id/rollback', async (request, reply) => {
    const { id } = request.params as { id: string };
    const result = await service.rollback(id);

    return reply.send({ success: true, data: result });
  });
}
