**Step 1: 完善后端事件广播** (1天)

```typescript
// src/dashboard/services/realtime.service.ts
export class RealtimeService {
  private clients: Set<WebSocket> = new Set()

  // 广播迭代状态变化
  broadcastIterationStatus(iteration: Iteration) {
    this.broadcast({
      type: 'iteration.status_changed',
      data: {
        id: iteration.id,
        status: iteration.status,
        progress: iteration.progress
      }
    })
  }

  // 广播迭代进度
  broadcastIterationProgress(iterationId: string, progress: number) {
    this.broadcast({
      type: 'iteration.progress',
      data: { id: iterationId, progress }
    })
  }

  // 广播Agent状态
  broadcastAgentStatus(agent: Agent) {
    this.broadcast({
      type: 'agent.status_changed',
      data: agent
    })
  }

  // 广播系统指标
  broadcastSystemMetrics(metrics: SystemMetrics) {
    this.broadcast({
      type: 'system.metrics',
      data: metrics
    })
  }

  // 广播日志条目
  broadcastLogEntry(log: LogEntry) {
    this.broadcast({
      type: 'log.entry',
      data: log
    })
  }

  private broadcast(message: any) {
    const data = JSON.stringify(message)
    this.clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(data)
      }
    })
  }
