```typescript
// src/auto-iteration.ts
import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private iterationService: IterationService
  private realtimeService: RealtimeService
  private currentIteration: Iteration | null = null

  async initialize() {
    const services = getServices()
    this.iterationService = services.iterationService
    this.realtimeService = services.realtimeService
  }

  async startIteration(requirement: string) {
    // 创建迭代记录
    this.currentIteration = await this.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement,
      progress: 0
    })

    // 推送迭代开始
    this.realtimeService.broadcastIterationStatus(this.currentIteration)

    try {
      // 产品经理分析
      await this.runProductManager(requirement)

      // 架构师设计
      await this.runArchitect(requirement)

      // 前端开发
      await this.runFrontend(requirement)

      // 后端开发
      await this.runBackend(requirement)

      // 数据库设计
      await this.runDatabase(requirement)

      // 测试
      await this.runTest(requirement)

      // 更新为成功
      await this.completeIteration('success')
    } catch (error) {
      await this.completeIteration('failed', error.message)
    }
  }

  private async runProductManager(requirement: string) {
    // 推送Agent状态
    this.realtimeService.broadcastAgentStatus({
      name: 'product-manager',
      status: 'running',
      currentTask: '分析需求中...'
    })

    // 执行Agent
    const result = await this.productManager.execute(requirement)

    // 推送Agent完成
    this.realtimeService.broadcastAgentStatus({
      name: 'product-manager',
      status: 'success',
      currentTask: '需求分析完成'
    })

    // 更新进度
    this.currentIteration!.progress = 20
    this.realtimeService.broadcastIterationProgress(
      this.currentIteration!.id,
      20
    )
  }

  private async completeIteration(status: string, error?: string) {
    if (!this.currentIteration) return

    // 更新迭代状态
    await this.iterationService.update(this.currentIteration.id, {
      status,
      progress: status === 'success' ? 100 : this.currentIteration.progress,
      completedAt: new Date(),
      errorMessage: error
    })

    // 推送迭代完成
    this.realtimeService.broadcastIterationStatus({
      ...this.currentIteration,
      status,
      completedAt: new Date()
    })

    // Git提交
    if (status === 'success') {
      const commitResult = await this.gitCommit()
      await this.iterationService.addCommit(
        this.currentIteration.id,
        commitResult
      )
    }
  }
}
