```typescript
// dashboard/src/stores/websocket.ts
import { defineStore } from 'pinia'
import { ref } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const isConnected = ref(false)
  const reconnectAttempts = ref(0)
  const socket = ref<WebSocket | null>(null)

  function connect() {
    const wsUrl = import.meta.env.VITE_WS_BASE_URL || 'ws://localhost:3000/ws'
    socket.value = new WebSocket(wsUrl)

    socket.value.onopen = () => {
      isConnected.value = true
      reconnectAttempts.value = 0
      console.log('✅ WebSocket 已连接')

      // 订阅所有频道
      subscribe('iterations')
      subscribe('agents')
      subscribe('logs')
      subscribe('metrics')
    }

    socket.value.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data)
        handleMessage(message)
      } catch (error) {
        console.error('WebSocket 消息解析错误:', error)
      }
    }

    socket.value.onclose = () => {
      isConnected.value = false
      console.log('❌ WebSocket 已断开')

      // 自动重连
      if (reconnectAttempts.value < 5) {
        setTimeout(() => {
          reconnectAttempts.value++
          console.log(`🔄 尝试重连 (${reconnectAttempts.value}/5)...`)
          connect()
        }, 1000 * reconnectAttempts.value)
      }
    }

    socket.value.onerror = (error) => {
      console.error('WebSocket 错误:', error)
    }
  }

  function subscribe(channel: string) {
    if (socket.value?.readyState === WebSocket.OPEN) {
      socket.value.send(JSON.stringify({
        type: 'subscribe',
        channel
      }))
    }
  }

  function handleMessage(message: any) {
    const { type, data } = message

    switch (type) {
      case 'iteration.status_changed':
        useIterationStore().updateIteration(data)
        break
      case 'iteration.progress':
        useIterationStore().updateProgress(data.id, data.progress)
        break
      case 'agent.status_changed':
        useAgentStore().updateAgent(data)
        break
      case 'agent.progress':
        useAgentStore().updateAgentProgress(data.name, data.progress)
        break
      case 'system.metrics':
        useOverviewStore().updateMetrics(data)
        break
      case 'log.entry':
        useLogStore().addLogEntry(data)
        break
      case 'iteration.completed':
        useIterationStore().markIterationCompleted(data)
        ElMessage.success(`迭代 #${data.iteration.iterationNumber} 已完成`)
        break
      case 'error':
        ElMessage.error(data.message)
        break
    }
  }

  return {
    isConnected,
    connect,
    subscribe
  }
})
```

