### 🔴 P0-0.2: AutoIterationEngine 与 Dashboard 集成

#### 技术方案

**目标**: 让 AutoIterationEngine 在执行过程中推送实时状态到 Dashboard

**实施方案**:

```typescript
// 1. 修改 src/auto-iteration.ts
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private iterationService?: any;
  private realtimeService?: any;
  private currentIterationId?: string;

  constructor(config: Partial<IterationConfig> = {}) {
    // ... 现有代码 ...

    // 尝试获取 Dashboard 服务（如果已启动）
    try {
      const services = getServices();
      this.iterationService = services.iterationService;
      this.realtimeService = services.realtimeService;
      console.log('✅ Dashboard 服务已连接');
    } catch (error) {
      console.log('ℹ️ Dashboard 服务未启动，跳过实时推送');
    }
  }

  async start(): Promise<void> {
    // ... 现有代码 ...

    while (this.isRunning) {
      this.iterationCount++;

      // 🆕 创建迭代记录
      if (this.iterationService) {
        const iteration = await this.iterationService.create({
          iterationNumber: this.iterationCount,
          status: 'running',
          requirement: '自动迭代',
          createdAt: new Date()
        });
        this.currentIterationId = iteration.id;

        // 推送状态
        this.realtimeService?.broadcastIterationStatusChange(iteration);
      }

      try {
        await this.runIteration();
      } catch (error) {
        // 推送失败状态
        if (this.realtimeService && this.currentIterationId) {
          await this.iterationService?.update(this.currentIterationId, {
            status: 'failed',
            errorMessage: String(error)
          });
          this.realtimeService.broadcastIterationStatusChange({
            id: this.currentIterationId,
            status: 'failed'
          });
        }
      }
    }
  }

  private async runIteration(): Promise<void> {
    // 🆕 产品经理阶段
    await this.runPhase('product-manager', async () => {
      const task = await this.productManager.execute('发现需求');

      // 推送 Agent 状态
      if (this.realtimeService) {
        this.realtimeService.broadcastAgentStatusChange({
          name: 'product-manager',
          status: 'success',
          currentTask: '需求分析完成'
        });
      }

      return task;
    });

    // 🆕 其他 Agent 阶段...
    await this.runPhase('architect', async () => {
      // ...
      this.realtimeService?.broadcastAgentStatusChange({
        name: 'architect',
        status: 'success',
        currentTask: '架构设计完成'
      });
    });

    // 🆕 迭代完成
    if (this.realtimeService && this.currentIterationId) {
      await this.iterationService?.update(this.currentIterationId, {
        status: 'success',
        progress: 100,
        completedAt: new Date()
      });

      this.realtimeService.broadcastIterationStatusChange({
        id: this.currentIterationId,
        status: 'success',
        progress: 100
      });
    }
  }

  private async runPhase(
    agentName: string, 
    phaseFn: () => Promise<any>
  ): Promise<any> {
    // 推送开始
    this.realtimeService?.broadcastAgentStatusChange({
      name: agentName,
      status: 'running',
      currentTask: `${agentName} 执行中...`
    });

    // 执行
    const result = await phaseFn();

    // 推送进度
    const progress = this.calculateProgress();
    if (this.realtimeService && this.currentIterationId) {
      this.realtimeService.broadcastIterationProgress({
        iterationId: this.currentIterationId,
        progress
      });
    }

    return result;
  }

  private calculateProgress(): number {
    // 根据 Agent 执行情况计算进度
    const totalPhases = 9; // 10 个 Agent
    return Math.floor((this.completedPhases / totalPhases) * 100);
  }
}
