// 2. 修改 src/main.ts
import { startDashboard } from './dashboard/server';
import { AutoIterationEngine } from './auto-iteration';

interface Config {
  auto: boolean;
  interval: number;
  max: number;
  dashboard?: boolean;
  dashboardPort?: number;
}

function parseConfig(): Config {
  const args = process.argv.slice(2);

  return {
    auto: args.includes('--auto'),
    interval: parseInt(getArgValue('--interval') || '60'),
    max: parseInt(getArgValue('--max') || '0'),
    dashboard: args.includes('--dashboard') || process.env.DASHBOARD_ENABLED === 'true',
    dashboardPort: parseInt(process.env.DASHBOARD_PORT || '3000')
  };
}

async function main() {
  printBanner();

  const config = parseConfig();

  // 🆕 启动 Dashboard（如果启用）
  if (config.dashboard) {
    try {
      console.log('🚀 启动 Dashboard 服务...');
      await startDashboard();
      console.log(`✅ Dashboard 已启动: http://localhost:${config.dashboardPort}`);
    } catch (error) {
      console.error('❌ Dashboard 启动失败:', error);
      if (!config.auto) {
        // 如果不是自动模式，退出
        process.exit(1);
      }
    }
  }

  // 启动自动迭代
  if (config.auto) {
    await runAutoIteration(config);
  } else {
    await runInteractive();
  }
}

