虽然 WebSocketManager 已完善，但需要确保消息正确分发到各个 Store：

```typescript
// 3. 检查/创建 src/stores/_websocket.ts
import { useWebSocket } from '@/utils/websocket-manager';
import { useIterationStore } from './iteration';
import { useAgentStore } from './agent';
import { useOverviewStore } from './overview';
import { ElMessage } from 'element-plus';

export function initWebSocketMessaging() {
  const wsManager = useWebSocket();
  const iterationStore = useIterationStore();
  const agentStore = useAgentStore();
  const overviewStore = useOverviewStore();

  // 监听迭代状态变化
  wsManager.on('iteration.status_changed', (data) => {
    iterationStore.updateIteration(data);
  });

  // 监听迭代进度
  wsManager.on('iteration.progress', (data) => {
    iterationStore.updateProgress(data.iterationId, data.progress);
  });

  // 监听 Agent 状态变化
  wsManager.on('agent.status_changed', (data) => {
    agentStore.updateAgent(data);
  });

  // 监听系统指标
  wsManager.on('system.metrics', (data) => {
    overviewStore.updateMetrics(data);
  });

  // 监听日志
  wsManager.on('log.entry', (data) => {
    // TODO: 实现日志 Store
  });

  // 监听迭代完成
  wsManager.on('iteration.completed', (data) => {
    ElMessage.success(`迭代 #${data.iteration.iterationNumber} 已完成`);
    iterationStore.markIterationCompleted(data);
  });

  // 监听错误
  wsManager.on('error', (data) => {
    ElMessage.error(data.message);
  });
}
```

